import { createApp } from 'vue'
import App from './App.vue'
import PrimeVue from 'primevue/config';
import Skeleton from 'primevue/skeleton';

const app = createApp(App)

app.use(PrimeVue)
app.component("Skeleton", Skeleton)
app.mount('#app')
